import { motion } from 'framer-motion';
import SectionWrapper, { SectionTitle } from './SectionWrapper';
import { ExternalLink, Github, Star } from 'lucide-react';

const projects = [
  {
    title: 'MERN Study Assistant',
    description: 'AI-powered study platform with personalized quiz generation, progress tracking, and real-time collaboration. Supports 200+ concurrent sessions.',
    tags: ['MongoDB', 'Express', 'React', 'Node.js', 'OpenAI'],
    color: '#6366f1',
    gradient: 'from-indigo-500/20 to-purple-500/10',
    stars: 128,
    demo: '#',
    github: '#',
    featured: true,
  },
  {
    title: 'E-Commerce Platform',
    description: 'Full-stack marketplace with Stripe payments, inventory management, real-time order tracking, and an analytics admin dashboard.',
    tags: ['React', 'Node.js', 'MongoDB', 'Stripe', 'Redux'],
    color: '#a855f7',
    gradient: 'from-purple-500/20 to-pink-500/10',
    stars: 94,
    demo: '#',
    github: '#',
  },
  {
    title: 'DevConnect Social',
    description: 'Developer-focused social network with real-time messaging via Socket.io, code snippet sharing with syntax highlighting, and GitHub OAuth.',
    tags: ['React', 'Socket.io', 'Express', 'MongoDB'],
    color: '#06b6d4',
    gradient: 'from-cyan-500/20 to-blue-500/10',
    stars: 76,
    demo: '#',
    github: '#',
  },
  {
    title: 'Task Manager API',
    description: 'Production-grade REST API with role-based access, JWT refresh tokens, rate limiting, comprehensive Swagger docs, and Docker deployment.',
    tags: ['Node.js', 'Express', 'MongoDB', 'Docker', 'JWT'],
    color: '#22c55e',
    gradient: 'from-green-500/20 to-emerald-500/10',
    stars: 55,
    demo: '#',
    github: '#',
  },
  {
    title: 'Weather Dashboard',
    description: 'Interactive weather app with geolocation, 7-day forecasts, hourly charts, and animated weather conditions using OpenWeather API.',
    tags: ['React', 'Chart.js', 'OpenWeather API', 'Tailwind'],
    color: '#f59e0b',
    gradient: 'from-amber-500/20 to-orange-500/10',
    stars: 42,
    demo: '#',
    github: '#',
  },
  {
    title: 'Portfolio CMS',
    description: 'Headless CMS for portfolio management with drag-and-drop builder, markdown editor, media library, and one-click deployment.',
    tags: ['Next.js', 'MongoDB', 'AWS S3', 'TailwindCSS'],
    color: '#ec4899',
    gradient: 'from-pink-500/20 to-rose-500/10',
    stars: 31,
    demo: '#',
    github: '#',
  },
];

function ProjectCard({ project, index }) {
  return (
    <motion.div
      initial={{ opacity: 0, y: 30 }}
      whileInView={{ opacity: 1, y: 0 }}
      viewport={{ once: true, margin: '-40px' }}
      transition={{ duration: 0.5, delay: (index % 3) * 0.1 }}
      whileHover={{ y: -8, transition: { duration: 0.25 } }}
      className="group glass-card rounded-2xl border border-slate-700/50 overflow-hidden hover:border-slate-600/70 transition-all duration-300 hover:shadow-2xl flex flex-col"
      style={{ '--accent': project.color }}
    >
      {/* Image placeholder / gradient banner */}
      <div className={`relative h-44 bg-gradient-to-br ${project.gradient} border-b border-slate-700/30 overflow-hidden`}>
        <div
          className="absolute inset-0 opacity-10"
          style={{
            backgroundImage: 'linear-gradient(rgba(255,255,255,0.05) 1px, transparent 1px), linear-gradient(90deg, rgba(255,255,255,0.05) 1px, transparent 1px)',
            backgroundSize: '24px 24px',
          }}
        />
        {/* Mock UI shapes */}
        <div className="absolute inset-4 rounded-xl border border-white/5 bg-white/2" />
        <div
          className="absolute top-8 left-8 right-8 h-3 rounded-full opacity-30"
          style={{ background: project.color }}
        />
        <div className="absolute top-16 left-8 w-2/3 h-2 rounded-full bg-white/10" />
        <div className="absolute top-22 left-8 w-1/2 h-2 rounded-full bg-white/8" />
        <div
          className="absolute bottom-4 right-4 w-16 h-16 rounded-2xl opacity-20"
          style={{ background: `radial-gradient(circle, ${project.color}, transparent)` }}
        />

        {project.featured && (
          <div className="absolute top-3 left-3 px-2.5 py-1 text-xs font-bold bg-indigo-500 text-white rounded-lg shadow-lg">
            Featured
          </div>
        )}

        {/* Stars */}
        <div className="absolute top-3 right-3 flex items-center gap-1 px-2 py-1 bg-slate-900/70 rounded-lg text-xs text-amber-400">
          <Star size={10} fill="currentColor" />
          {project.stars}
        </div>
      </div>

      <div className="p-5 flex flex-col flex-1">
        <h3 className="text-white font-bold text-lg mb-2 group-hover:text-indigo-300 transition-colors" style={{ fontFamily: 'Syne, sans-serif' }}>
          {project.title}
        </h3>
        <p className="text-slate-400 text-sm leading-relaxed mb-4 flex-1">{project.description}</p>

        {/* Tags */}
        <div className="flex flex-wrap gap-1.5 mb-4">
          {project.tags.map((tag) => (
            <span
              key={tag}
              className="text-xs px-2.5 py-1 rounded-md text-slate-400 border border-slate-700/60 hover:border-slate-600"
            >
              {tag}
            </span>
          ))}
        </div>

        {/* Links */}
        <div className="flex gap-3 pt-4 border-t border-slate-700/40">
          <a
            href={project.demo}
            className="flex items-center gap-1.5 text-xs font-semibold text-white px-4 py-2 rounded-lg transition-all flex-1 justify-center"
            style={{ background: project.color + '22', border: `1px solid ${project.color}44` }}
          >
            <ExternalLink size={13} />
            Live Demo
          </a>
          <a
            href={project.github}
            className="flex items-center gap-1.5 text-xs font-medium text-slate-400 hover:text-white border border-slate-700 hover:border-slate-500 px-4 py-2 rounded-lg transition-all flex-1 justify-center"
          >
            <Github size={13} />
            GitHub
          </a>
        </div>
      </div>
    </motion.div>
  );
}

export default function Projects() {
  return (
    <SectionWrapper id="projects" className="bg-slate-900/20">
      <SectionTitle
        label="Portfolio"
        title="Featured Projects"
        subtitle="A selection of projects that showcase my skills in full-stack development, API design, and real-world problem solving."
      />
      <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
        {projects.map((project, i) => (
          <ProjectCard key={project.title} project={project} index={i} />
        ))}
      </div>

      <motion.div
        initial={{ opacity: 0 }}
        whileInView={{ opacity: 1 }}
        viewport={{ once: true }}
        className="text-center mt-12"
      >
        <a
          href="https://github.com"
          className="inline-flex items-center gap-2 px-6 py-3 border border-slate-700 hover:border-indigo-500/50 text-slate-400 hover:text-white rounded-xl text-sm font-medium transition-all hover:-translate-y-0.5"
        >
          <Github size={16} />
          View all on GitHub
        </a>
      </motion.div>
    </SectionWrapper>
  );
}
